def login_redirect(next_url="/"):
    from urllib.parse import urlparse

    if not next_url:
        return "/"

    parsed = urlparse(next_url)

    if parsed.scheme or parsed.netloc:
        return "/"

    if not next_url.startswith("/"):
        return "/"

    return next_url


def authenticate_and_redirect(user, password, next_url="/"):
    authenticated = authenticate_user(user, password)
    if authenticated:
        return {"status": "ok", "redirect_to": login_redirect(next_url)}
    return {"status": "error", "redirect_to": "/login"}


def authenticate_user(user, password):
    return bool(user) and bool(password)